import React, { useMemo, useCallback, useContext } from 'react';
import { useLocation, useHistory } from 'react-router-dom';
import classNames from 'classnames';
import PropTypes from 'prop-types';
import { NewsContext } from '../../NewsProvider';
import { Loader } from '../Loader';
import './HomePage.scss';

export const HomePage = ({ newsTrending, newsCategory, setArticle }) => {
  const location = useLocation('');
  const searchParams = new URLSearchParams(location.search);
  const history = useHistory();
  const category = searchParams.get('category');
  const { appliedQuery, setClick, setPath } = useContext(NewsContext);
  // const [preview, setPreview] = useState();
  const visiblePreview = useMemo(() => {
    return (category ? newsCategory : newsTrending)
      .find(item => (
        item.title.toLowerCase()
          .includes(appliedQuery.toLowerCase())));
  }, [category, newsCategory, newsTrending, appliedQuery]);

  const vis = useCallback(() => {
    setArticle(visiblePreview);
  }, [visiblePreview]);

  const prev = useCallback((item) => {
    setArticle(item);
  }, []);

  // if (newsTrending.length === 0) {
  //   return <Loader />;
  // }

  console.log(visiblePreview);
  console.log(prev);

  return (
    <div className="HomePage">
      {(visiblePreview && appliedQuery) && (
        <div className={classNames('HomePage-Preview Preview', {
          is_visible: {},
        })}
        >
          <div className="Preview-Content">
            <button
              type="button"
              className="Preview-Title"
              onClick={() => {}}
            >
              {(visiblePreview.title)
                .length > 90
                ? `${visiblePreview.title.slice(0, 85)}...`
                : visiblePreview.title}
            </button>
            <p className="Preview-Description">
              {(visiblePreview.description)
                .length > 350
                ? `${visiblePreview.description.slice(0, 160)}...`
                : visiblePreview.description}
            </p>
            <div className="Preview-Read">
              <p className="Preview-Date">
                {new Date(visiblePreview.publishedAt
                  .slice(0, 10)).toString().slice(4, 15)}
              </p>
              <button
                type="button"
                className="Preview-Button"
                onClick={() => {
                  vis();
                  setClick(true);
                  history.push('/articles');
                }}
              >
                Read more
              </button>
            </div>
          </div>
          <div className="Preview-Image">
            <img
              className="image-preview"
              src={visiblePreview.image}
              height="300"
              alt="Foto"
            />
          </div>
        </div>
      )}

      <div className="HomePage-Container">
        {(category ? newsCategory : newsTrending).map((item, index) => (
          <div
            className="HomePage-ContentNews News"
            key={`${item.title + index}`}
          >
            <img
              className="News-Image"
              src={item.image || '../images/no_image.jpeg'}
              height="183"
              alt="Foto"
            />
            <div className="News-Content">
              <h3 className="News-Title"

              >
                {(item.title).length > 83
                  ? `${item.title.slice(0, 70)}...`
                  : item.title}
              </h3>
              <p className="News-Description">
                {(item.description).length > 160
                  ? `${item.description.slice(0, 155)}...`
                  : item.description}
              </p>
              <div className="News-Read">
                <p className="News-Date">
                  {new Date(item.publishedAt
                    .slice(0, 10)).toString().slice(4, 15)}
                </p>
                <button
                  type="button"
                  className="News-Button"
                  onClick={() => {
                    prev(item);
                    setClick(true);
                    history.push('/articles');
                    setPath('/articles');
                  }}
                >
                  Read more
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

HomePage.propTypes = {
  newsTrending: PropTypes.arrayOf({
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
  }.isRequired).isRequired,
  newsCategory: PropTypes.arrayOf({
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
  }.isRequired),
  setArticle: PropTypes.func.isRequired,
};

HomePage.defaultProps = {
  newsCategory: [],
};
